function initEditionCoin(canvas, metalColor, frontTex, backTex) {
  const gl = canvas.getContext('webgl', { antialias: true, alpha: true });
  if (!gl) return null;

  const vsSource = `
    attribute vec3 aPos;
    attribute vec3 aNorm;
    attribute vec2 aUV;
    uniform mat4 uProj;
    uniform mat4 uView;
    uniform mat4 uModel;
    varying vec3 vNorm;
    varying vec3 vWorldPos;
