    uniform vec3 uLightDir;
    uniform vec3 uEyePos;
    uniform vec3 uBaseColor;
    uniform float uTime;
    void main() {
      vec3 N = normalize(vNorm);
      vec3 L = normalize(uLightDir);
      vec3 V = normalize(uEyePos - vWorldPos);
      vec3 H = normalize(L + V);
      float diff = max(dot(N, L), 0.0);
      float spec = pow(max(dot(N, H), 0.0), 80.0);
      float rim = pow(1.0 - max(dot(N, V), 0.0), 3.0);
      vec4 texColor = texture2D(uTex, vUV);
      vec3 ambient = uBaseColor * 0.15;
      vec3 diffuse = uBaseColor * diff * 0.7;
      vec3 specular = vec3(1.0) * spec * 0.9;
      vec3 rimColor = vec3(0.9, 0.8, 0.5) * rim * 0.25;
      vec3 color = ambient + diffuse + specular + rimColor;
      color = mix(color, texColor.rgb, 0.6);
      gl_FragColor = vec4(color, 1.0);
    }
  `;

  const vs = createShader(gl, gl.VERTEX_SHADER, vsSource);
  const fs = createShader(gl, gl.FRAGMENT_SHADER, fsSource);
  const prog = createProgram(gl, vs, fs);
  if (!prog) return null;

  const geo = buildCoinGeometry(64);

  const vBuf = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, vBuf);
  gl.bufferData(gl.ARRAY_BUFFER, geo.verts, gl.STATIC_DRAW);

  const nBuf = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, nBuf);
  gl.bufferData(gl.ARRAY_BUFFER, geo.norms, gl.STATIC_DRAW);

  const uBuf = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, uBuf);
  gl.bufferData(gl.ARRAY_BUFFER, geo.uvs, gl.STATIC_DRAW);

  const iBuf = gl.createBuffer();
  gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, iBuf);
  gl.bufferData(gl.ELEMENT_ARRAY_BUFFER, geo.indices, gl.STATIC_DRAW);

  const aPos = gl.getAttribLocation(prog, 'aPos');
  const aNorm = gl.getAttribLocation(prog, 'aNorm');
  const aUV = gl.getAttribLocation(prog, 'aUV');

  gl.enableVertexAttribArray(aPos);
  gl.bindBuffer(gl.ARRAY_BUFFER, vBuf);
  gl.vertexAttribPointer(aPos, 3, gl.FLOAT, false, 0, 0);

  gl.enableVertexAttribArray(aNorm);
  gl.bindBuffer(gl.ARRAY_BUFFER, nBuf);
  gl.vertexAttribPointer(aNorm, 3, gl.FLOAT, false, 0, 0);

  gl.enableVertexAttribArray(aUV);
  gl.bindBuffer(gl.ARRAY_BUFFER, uBuf);
  gl.vertexAttribPointer(aUV, 2, gl.FLOAT, false, 0, 0);

  function makeTexture(canvas) {
    const tex = gl.createTexture();
    gl.bindTexture(gl.TEXTURE_2D, tex);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, canvas);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
    return tex;
  }

  const frontTexGL = makeTexture(frontTex);
  const backTexGL = makeTexture(backTex);

  const uProj = gl.getUniformLocation(prog, 'uProj');
  const uView = gl.getUniformLocation(prog, 'uView');
  const uModel = gl.getUniformLocation(prog, 'uModel');
  const uLightDir = gl.getUniformLocation(prog, 'uLightDir');
  const uEyePos = gl.getUniformLocation(prog, 'uEyePos');
  const uTex = gl.getUniformLocation(prog, 'uTex');
  const uBaseColor = gl.getUniformLocation(prog, 'uBaseColor');
  const uTime = gl.getUniformLocation(prog, 'uTime');

  function perspective(fov, aspect, near, far) {
    const f = 1.0 / Math.tan(fov / 2);
    const nf = 1 / (near - far);
    return new Float32Array([
      f/aspect, 0, 0, 0,
      0, f, 0, 0,
      0, 0, (far+near)*nf, -1,
      0, 0, 2*far*near*nf, 0
    ]);
  }

  function lookAt(eye, center, up) {
    const zx = eye[0]-center[0], zy = eye[1]-center[1], zz = eye[2]-center[2];
    let len = 1/Math.sqrt(zx*zx+zy*zy+zz*zz);
    const fz = [zx*len, zy*len, zz*len];
    const sx = up[1]*fz[2]-up[2]*fz[1], sy = up[2]*fz[0]-up[0]*fz[2], sz = up[0]*fz[1]-up[1]*fz[0];
    len = 1/Math.sqrt(sx*sx+sy*sy+sz*sz);
    const fs = [sx*len, sy*len, sz*len];
    const ux = fz[1]*fs[2]-fz[2]*fs[1], uy = fz[2]*fs[0]-fz[0]*fs[2], uz = fz[0]*fs[1]-fz[1]*fs[0];
    return new Float32Array([
      fs[0], ux, fz[0], 0,
      fs[1], uy, fz[1], 0,
      fs[2], uz, fz[2], 0,
      -(fs[0]*eye[0]+fs[1]*eye[1]+fs[2]*eye[2]),
      -(ux*eye[0]+uy*eye[1]+uz*eye[2]),
      -(fz[0]*eye[0]+fz[1]*eye[1]+fz[2]*eye[2]),
      1
    ]);
  }

  function multiply(a, b) {
    const r = new Float32Array(16);
    for (let i = 0; i < 4; i++)
      for (let j = 0; j < 4; j++) {
        r[j*4+i] = 0;
        for (let k = 0; k < 4; k++)
          r[j*4+i] += a[k*4+i] * b[j*4+k];
      }
    return r;
  }

  function rotateY(a) {
    const c = Math.cos(a), s = Math.sin(a);
    return new Float32Array([c,0,s,0, 0,1,0,0, -s,0,c,0, 0,0,0,1]);
  }

  function rotateX(a) {
    const c = Math.cos(a), s = Math.sin(a);
    return new Float32Array([1,0,0,0, 0,c,-s,0, 0,s,c,0, 0,0,0,1]);
  }

  function render(t, metalColor) {
    const W = canvas.width, H = canvas.height;
    gl.viewport(0, 0, W, H);
    gl.clearColor(0.07, 0.07, 0.1, 1.0);
    gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);
    gl.enable(gl.DEPTH_TEST);
    gl.enable(gl.CULL_FACE);
    gl.cullFace(gl.BACK);

    const aspect = W / H;
    const proj = perspective(Math.PI / 4, aspect, 0.1, 100);
    const view = lookAt([0, 0, 3.5], [0, 0, 0], [0, 1, 0]);

    const rotY = t * Math.PI * 2;
    const flipX = Math.sin(t * Math.PI * 2) * Math.PI * 0.45;
    const model = multiply(rotateY(rotY), rotateX(flipX));

    gl.useProgram(prog);
    gl.uniformMatrix4fv(uProj, false, proj);
    gl.uniformMatrix4fv(uView, false, view);
    gl.uniformMatrix4fv(uModel, false, model);
    gl.uniform3f(uEyePos, 0, 0, 3.5);

    const lightAngle = t * Math.PI * 2 + Math.PI * 0.25;
    const lightX = Math.cos(lightAngle) * 2;
    const lightY = Math.sin(lightAngle * 0.7) * 1.5;
    const lightZ = Math.sin(lightAngle) * 2;
    const lLen = Math.sqrt(lightX*lightX + lightY*lightY + lightZ*lightZ);
    gl.uniform3f(uLightDir, lightX/lLen, lightY/lLen, lightZ/lLen);
    gl.uniform1f(uTime, t);

    // Front
    gl.uniform1i(uTex, 0);
    gl.activeTexture(gl.TEXTURE0);
    gl.bindTexture(gl.TEXTURE_2D, frontTexGL);
    gl.uniform3f(uBaseColor, metalColor[0], metalColor[1], metalColor[2]);
    gl.cullFace(gl.BACK);
    gl.drawElements(gl.TRIANGLES, geo.count, gl.UNSIGNED_SHORT, 0);

    // Back
    gl.uniform1i(uTex, 1);
    gl.activeTexture(gl.TEXTURE0);
    gl.bindTexture(gl.TEXTURE_2D, backTexGL);
    gl.uniform3f(uBaseColor, metalColor[0], metalColor[1], metalColor[2]);
    gl.cullFace(gl.FRONT);
    gl.drawElements(gl.TRIANGLES, geo.count, gl.UNSIGNED_SHORT, 0);
    gl.cullFace(gl.BACK);
  }

  return { gl, prog, geo, render, perspective, lookAt, multiply, rotateY, rotateX };
}

