/* ============================================================
   ANIMATION LOOP
   ============================================================ */
let animTime = 0;
let animating = true;
let lastTimestamp = 0;
const ANIM_DURATION = 8; // seconds for full loop

function animate(timestamp) {
  if (!animating) return;
  if (!lastTimestamp) lastTimestamp = timestamp;
  const dt = (timestamp - lastTimestamp) / 1000;
  lastTimestamp = timestamp;
  animTime = (animTime + dt) % ANIM_DURATION;
  renderAll();
  requestAnimationFrame(animate);
}

function renderAll() {
  const t = animTime / ANIM_DURATION; // [0, 1]

  // Hero coin
  if (coinRenderer) {
    coinRenderer.render(t, [0.85, 0.7, 0.3]);
  }

  // Edition coins
  editionRenderers.forEach((renderer, i) => {
    if (renderer) {
      renderer.render(t, editionMetalColors[editionCanvases[i].parentElement.dataset.edition] || [0.85, 0.7, 0.3]);
    }
  });
}

requestAnimationFrame(animate);

/* ============================================================
   PUBLIC API
   ============================================================ */
window.demo = {
  canvas: heroCanvas,

  setTime(t) {
    // t in [0,1] -> render exactly that point of the loop
    t = ((t % 1) + 1) % 1;
    animTime = t * ANIM_DURATION;
    renderAll();
  },

  pause() {
    animating = false;
  }
};

